from django.db import migrations


def _list_fks_to_dimension_tables(cursor):
    """
    Legacy tenants often have FKs referencing dimension_dimension(code) /
    dimension_dimensionvalue(code). Postgres blocks dropping those PKs until
    dependent FKs are removed. Capture defs so we can recreate them against
    UNIQUE(code) after the PK moves to id.
    """
    cursor.execute(
        """
        SELECT con.conname, src.relname::text, pg_get_constraintdef(con.oid)
        FROM pg_constraint con
        JOIN pg_class src ON src.oid = con.conrelid
        JOIN pg_namespace ns ON ns.oid = src.relnamespace
        JOIN pg_class ref ON ref.oid = con.confrelid
        JOIN pg_namespace refns ON refns.oid = ref.relnamespace
        WHERE con.contype = 'f'
          AND refns.nspname = current_schema()
          AND ref.relname IN ('dimension_dimension', 'dimension_dimensionvalue')
        ORDER BY con.oid
        """
    )
    return cursor.fetchall()


